document.addEventListener("DOMContentLoaded",()=>{document.fonts.ready.then(()=>{splits.forEach(e=>{let r=document.querySelectorAll(e.selector);r.length&&r.forEach(r=>{new SplitText(r,{type:"words,chars,lines",mask:!!e.mask&&"lines",autoSplit:!0,wordsClass:e.wordsClass,onSplit(r){let t={opacity:e.opacity,filter:e.filter,rotate:e.rotate,stagger:e.stagger,duration:e.duration,delay:e.delay,ease:e.ease,scrollTrigger:{trigger:e.trigger,start:e.start,end:e.end,scrub:e.onScroll,markers:e.markers}};return e.color&&(t.color=e.color),e.yPercent&&(t.yPercent=e.yPercent),gsap.from(r[e.target],t)}})})})});let e;window.addEventListener("resize",()=>{clearTimeout(e),e=setTimeout(()=>{ScrollTrigger.refresh(),console.log("refreshed")},200)})});